insert into public.messages (
  conversation_id,
  direction,
  message_type,
  content,
  media_url,
  state_at_time,
  agent_used,
  extracted_data
)
values (
  {{ "'" + String($('WhatsApp Trigger').item.json.contacts[0].wa_id) + "'" }},
  'INBOUND',
  {{ "'" + String(($('WhatsApp Trigger').item.json.messages?.[0]?.type || 'text')).toUpperCase() + "'" }},
  {{
    (() => {
      const m = $('WhatsApp Trigger').item.json.messages?.[0] || {};
      const txt = m.text?.body || m.image?.caption || m.document?.caption || null;
      if (txt === null) return "null";
      return "'" + String(txt).replace(/'/g, "''") + "'";
    })()
  }},
  {{
    (() => {
      const m = $('WhatsApp Trigger').item.json.messages?.[0] || {};
      const id = m.image?.id || m.document?.id || null;
      if (id === null) return "null";
      return "'" + String(id).replace(/'/g, "''") + "'";
    })()
  }},
  {{ "'" + String($json.conversation?.[0]?.current_state || 'QUALIFYING') + "'" }},
  'USER',
  '{}'::jsonb
)
returning id, created_at;

