/**
 * n8n Code node (recomendado: Run Once for Each Item)
 * Parsea el output con ```json ... ``` aunque tenga newlines ilegales dentro de strings.
 * Devuelve: final_whatsapp_text, post_actions, parsed, tool_output_parsed
 */

function stripCodeFences(str) {
  if (!str) return '';
  let s = String(str).trim();
  s = s.replace(/^\s*```json\s*/i, '');
  s = s.replace(/^\s*```\s*/i, '');
  s = s.replace(/\s*```\s*$/i, '');
  return s.trim();
}

function extractFirstJsonObject(text) {
  const s = String(text);
  const start = s.indexOf('{');
  if (start === -1) return null;

  let depth = 0;
  let inString = false;
  let escape = false;

  for (let i = start; i < s.length; i++) {
    const ch = s[i];

    if (inString) {
      if (escape) escape = false;
      else if (ch === '\\') escape = true;
      else if (ch === '"') inString = false;
    } else {
      if (ch === '"') inString = true;
      else if (ch === '{') depth++;
      else if (ch === '}') depth--;
      if (depth === 0) return s.slice(start, i + 1);
    }
  }
  return null;
}

function escapeControlCharsInsideStrings(jsonLike) {
  const s = String(jsonLike);
  let out = '';
  let inString = false;
  let escape = false;

  for (let i = 0; i < s.length; i++) {
    const ch = s[i];
    const code = ch.charCodeAt(0);

    if (inString) {
      if (escape) { out += ch; escape = false; continue; }
      if (ch === '\\') { out += ch; escape = true; continue; }
      if (ch === '"') { out += ch; inString = false; continue; }

      if (ch === '\n') { out += '\\n'; continue; }
      if (ch === '\r') { out += '\\r'; continue; }
      if (ch === '\t') { out += '\\t'; continue; }

      if (code >= 0x00 && code <= 0x1F) {
        out += '\\u' + code.toString(16).padStart(4, '0');
        continue;
      }

      out += ch;
      continue;
    }

    if (ch === '"') { out += ch; inString = true; continue; }
    out += ch;
  }

  return out;
}

function safeJsonParseLenient(text) {
  if (text == null) return null;
  const fixed = escapeControlCharsInsideStrings(String(text).trim());

  try {
    return JSON.parse(fixed);
  } catch (e1) {
    const objBlock = extractFirstJsonObject(fixed);
    if (objBlock) {
      try { return JSON.parse(objBlock); }
      catch (e2) { return { _raw: fixed.slice(0, 4000), _parse_error: e2.message }; }
    }
    return { _raw: fixed.slice(0, 4000), _parse_error: e1.message };
  }
}

function parseFencedJsonString(str) {
  if (!str) return null;
  let s = stripCodeFences(str);
  s = s.replace(/^\s*json\s*/i, '').trim();
  const objBlock = extractFirstJsonObject(s) || s;
  return safeJsonParseLenient(objBlock);
}

function getRawOutput(itemJson) {
  if (itemJson && typeof itemJson.output === 'string') return itemJson.output;
  if (Array.isArray(itemJson) && typeof itemJson[0]?.output === 'string') return itemJson[0].output;
  if (itemJson?.output && Array.isArray(itemJson.output) && typeof itemJson.output[0]?.output === 'string') return itemJson.output[0].output;
  return null;
}

function parseOrchestrator(rawOutput) {
  if (!rawOutput) {
    return { parsed: null, tool_output_parsed: null, final_whatsapp_text: null, post_actions: null, _error: 'No raw output found' };
  }

  // Outer JSON
  const outer = stripCodeFences(rawOutput);
  const outerBlock = extractFirstJsonObject(outer) || outer;
  const parsed = safeJsonParseLenient(outerBlock);

  // post_actions
  let post_actions = null;
  if (parsed?.post_actions != null) {
    post_actions = (typeof parsed.post_actions === 'string')
      ? safeJsonParseLenient(parsed.post_actions)
      : parsed.post_actions;
  }

  // tool_output -> result -> inner fenced json
  let tool_output_parsed = null;
  try {
    const toolOutput = parsed?.tool_output;
    if (toolOutput && typeof toolOutput === 'object') {
      const firstKey = Object.keys(toolOutput)[0]; // e.g. qualifying_agent_response
      const resultStr = toolOutput?.[firstKey]?.result;

      if (typeof resultStr === 'string' && resultStr.length) {
        const resultArr = safeJsonParseLenient(resultStr);
        if (Array.isArray(resultArr) && resultArr[0]?.output) {
          tool_output_parsed = parseFencedJsonString(resultArr[0].output);
        } else {
          tool_output_parsed = resultArr;
        }
      }
    }
  } catch (e) {
    tool_output_parsed = { _parse_error: e.message };
  }

  const final_whatsapp_text =
    parsed?.final_whatsapp_text ??
    tool_output_parsed?.respuesta ??
    null;

  return { parsed, tool_output_parsed, final_whatsapp_text, post_actions };
}

// ✅ SOLO el item actual (evita N^2)
const item = $input.first();
const raw = getRawOutput(item.json);
const res = parseOrchestrator(raw);

return [{ json: res }];

